性食品中毒？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:32+00:00", "source_pdf_sha1": "cc67e03c2e5b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "339", "s": "2213", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "食品安全與衛生法規", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "食品衛生檢驗"}'::jsonb, NULL),
